"use strict";parserFactory.register("webnovelonline.com",()=>new WebNovelOnlineParser);class WebNovelOnlineParser extends Parser{constructor(){super()}getChapterUrls(e){let t=[...e.querySelectorAll("div.chapter-list a")].map(e=>util.hyperLinkToChapter(e));return Promise.resolve(t.reverse())}findContent(e){return Parser.findConstrutedContent(e)}extractTitleImpl(e){return e.querySelector("div.novel-dexc h1")}extractAuthor(e){let t=e.querySelector("div.novel-desc > div.info > p:nth-child(1) > span:nth-child(2)");return null===t?super.extractAuthor(e):t.textContent}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.book")}async fetchChapter(e){let t=await HttpClient.wrapFetch(e);return WebNovelOnlineParser.buildContentHtml(t.responseXML,e)}static buildContentHtml(e,t){let r=Parser.makeEmptyDocForContent(t);r.content.appendChild(e.querySelector("div.chapter-info h3"));let n=WebNovelOnlineParser.getStringWithContent(e);return n.includes("</p>")?WebNovelOnlineParser.addHtmlToDocument(r.content,n):WebNovelOnlineParser.addTextToDocument(r,n),r.dom}static addTextToDocument(e,t){let r=t.split("\n").filter(e=>null!==e&&0<e.length);for(let t of r){let r=e.dom.createElement("p");r.appendChild(e.dom.createTextNode(t)),e.content.appendChild(r)}}static addHtmlToDocument(e,t){t='<div id="raw">'+t+"</div>";let r=util.sanitize(t);e.appendChild(r.querySelector("div#raw"))}static getStringWithContent(e){let t=[...e.querySelectorAll("script")].map(e=>e.textContent).filter(e=>e.includes("window._INITIAL_DATA_")),r=t[0].indexOf("["),n=t[0].substring(r,t[0].length-1);return JSON.parse(n).filter(e=>null!=e&&void 0!==e.chapter)[0].chapter}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.novel-desc, div.summary")]}cleanInformationNode(e){util.removeChildElementsMatchingSelector(e,"div.action")}}